import React, { useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
  RadialLinearScale,
  Filler
} from "chart.js";
import { Bar, Doughnut } from "react-chartjs-2";
import {
  LayoutDashboard,
  BarChart2,
  FileSpreadsheet,
  Search,
  AlertTriangle,
  Users,
  Bell,
  Settings,
  ChevronLeft,
  ChevronRight,
  Activity,
  Upload,
  User,
  FileText,
  TrendingUp,
  Target,
  PieChart
} from "lucide-react";
import "./App.css";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  RadialLinearScale,
  Filler,
  Title,
  Tooltip,
  Legend
);

const API_BASE = "http://localhost:5000/api";

const COLORS = {
  primary: "#6366f1",
  secondary: "#8b5cf6",
  success: "#10b981",
  warning: "#f59e0b",
  danger: "#ef4444",
  dark: "#1e293b",
  darker: "#0f172a",
  light: "#94a3b8",
  lighter: "#cbd5e1"
};

export default function App() {
  const [activeTab, setActiveTab] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(true);

  return (
    <div className="app">
      {/* Sidebar */}
      <aside className={`sidebar ${sidebarOpen ? "open" : "closed"}`}>
        <div className="sidebar-header">
          <div className="logo">
            <PieChart size={30} color="#8b5cf6" />
            {sidebarOpen && (
              <div className="logo-text">
                <h2>ChurnIntel</h2>
                <p>Analytics Suite</p>
              </div>
            )}
          </div>
          <button
            className="sidebar-toggle"
            onClick={() => setSidebarOpen(!sidebarOpen)}
          >
            {sidebarOpen ? <ChevronLeft /> : <ChevronRight />}
          </button>
        </div>

        <nav className="sidebar-nav">
          <button
            className={`nav-item ${activeTab === "dashboard" ? "active" : ""}`}
            onClick={() => setActiveTab("dashboard")}
          >
            <LayoutDashboard size={18} />
            {sidebarOpen && <span>Dashboard</span>}
          </button>
          <button
            className={`nav-item ${activeTab === "analyze" ? "active" : ""}`}
            onClick={() => setActiveTab("analyze")}
          >
            <Search size={18} />
            {sidebarOpen && <span>Analyze</span>}
